defmodule WaltUi.Authentication.Auth0Test do
  use Repo.DataCase

  alias WaltUi.Authentication.Auth0

  describe "JWT validation" do
    @expired_jwt "eyJhbGciOiJSUzI1NiIsInR5cCI6IkpXVCIsImtpZCI6IkJZblBaWDExTnlaNUd2UVVXU1VjLSJ9..wv1jEcUGteUO18qFsOnOVR8fhYZtcg72UokNrPNUfMnjZzFFZtx2OjIl2qLKpTMyq1RSCFDJVkVGzyRdfuffRlb1FFV4Og7QYbdSBWKL-5x_D31ciwE09Qkh9mUdrana-4e6f-xb8CX9A6Z6JDpK2uDbqO58X9VPeJ2Qy2BjACpbiq-tEDHfZuIvFYi21xu__N2tNZIp4xye0RFRVvX7DEny6DMNggrFy1TxCHBWxO6-9W7EDQWzoRAFIYVoncJlyfryz0J5f5NDqLooRZbjZFKin5Fr68i21lQLD5Bk6r7vgjrlYzScnRdlSodNCxnipCopl-I3Bfrk3Zg6ddJhrA"
    @unexpired_date DateTime.from_unix!(1_718_019_871)

    test "jwt_expired? returns true for expired jwts" do
      assert Auth0.jwt_expired?(@expired_jwt) == true
    end

    test "jwt_expired? returns false for unexpired jwts" do
      assert Auth0.jwt_expired?(@expired_jwt, @unexpired_date) == false
    end
  end
end
